mapper.select:
SELECT r.reservation_id, r.visitor_name, r.phone, r.visit_date, r.headcount, r.status, r.created_at, p.name AS place_name, pay.amount, pay.payment_status FROM RESERVATION r JOIN PLACE p ON p.place_id = r.place_id LEFT JOIN PAYMENT pay ON pay.reservation_id = r.reservation_id WHERE r.place_id = #{placeId} AND p.member_id = #{bizMemberId}
AND r.status = #{status}
ORDER BY r.visit_date DESC, r.reservation_id DESC

mapper.update:
UPDATE RESERVATION r
JOIN PLACE p ON p.place_id = r.place_id
SET r.status = #{status}
WHERE r.reservation_id = #{reservationId}
  AND p.member_id = #{bizMemberId}

UPDATE PLACE
SET is_closed = #{isClosed}
WHERE place_id = #{placeId}
  AND member_id = #{bizMemberId}
